const club = $('Get Club').first().json;
const url = (club.website_url || '').trim();
const isLive = (c) => (c >= 200 && c < 400) || c === 401 || c === 403 || c === 429; // exists (maybe bot-blocked)
let live = false;
if (url) {
  try {
    const res = await this.helpers.httpRequest({ method:'GET', url, timeout:8000, returnFullResponse:true, ignoreHttpStatusErrors:true, followRedirect:true, headers:{'User-Agent':'Mozilla/5.0 (compatible; leblovina)'} });
    live = isLive(res.statusCode || 0);
  } catch(e) { live = false; }   // DNS fail / timeout / refused -> dead
}
const stop = new Set(['volley','volleyball','voley','voleibol','pallavolo','club','clube','klub','kluby','asd','ssd','polisportiva','associazione','association','sportiva','sport','sports','team','siatkowki','siatkowka','the','de','di','del','la','el','of','and','vc','cv','vbc','vk']);
const tokens = String(club.name||'').toLowerCase().normalize('NFD').replace(/\p{M}/gu,'').replace(/[^\p{L}\p{N}\s]/gu,' ').split(/\s+/).filter(t => t.length>=3 && !stop.has(t));
const q = [club.name, club.city, club.country, 'volleyball'].filter(Boolean).join(' ');
return [{ json: { clubId: club.id, name: club.name, city: club.city, country: club.country, currentUrl: url, live, needsResolve: !live, nameTokens: tokens, query: q } }];

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const v = $('Validate').first().json; const clubId = v.clubId;
const patch = (body) => this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+clubId, headers:pbH, body, json:true });

if (v.live) { await patch({ website_status:'live' }); return [{ json:{ ok:true, clubId, action:'live', url:v.currentUrl } }]; }

const organic = ($('Serper Search').first().json.organic) || [];
const blocked = /(facebook|instagram|twitter|x\.com|linkedin|youtube|tiktok|wikipedia|volleybox|sofascore|flashscore|transfermarkt|eurosport|maps\.google|google\.|tripadvisor|yelp|amazon|\.gov)/i;
const isLive = (c) => (c >= 200 && c < 400) || c === 401 || c === 403 || c === 429;
let chosen = '';
for (const r of organic) {
  const link = (r.link || '').trim(); if (!/^https?:\/\//i.test(link)) continue;
  let host; try { host = new URL(link).hostname.replace(/^www\./,''); } catch(e) { continue; }
  if (blocked.test(host)) continue;
  const hay = (host + ' ' + (r.title||'')).toLowerCase();
  if (v.nameTokens.length && v.nameTokens.filter(t => hay.includes(t)).length < 1) continue;   // require a name-token match (skip when the name yields no usable tokens, e.g. all-symbol names)
  const cand = 'https://' + host;
  try { const res = await this.helpers.httpRequest({ method:'GET', url:cand, timeout:8000, returnFullResponse:true, ignoreHttpStatusErrors:true, followRedirect:true, headers:{'User-Agent':'Mozilla/5.0 (compatible; leblovina)'} }); if (isLive(res.statusCode||0)) { chosen = cand; break; } } catch(e) {}
}
if (chosen) { await patch({ website_url:chosen, website_source:'serper', website_status:'live' }); return [{ json:{ ok:true, clubId, action:'resolved', url:chosen } }]; }
const status = v.currentUrl ? 'dead' : 'not_found';   // had a URL that 404'd -> dead; never had one -> not_found
await patch({ website_url:'', website_source:'none', website_status:status });
return [{ json:{ ok:true, clubId, action:status } }];
